mapper.select:
SELECT o.ORG_ID, o.ORG_CODE, o.ORG_NAME,o.PARENT_ID,o.INHERITED_ID,
o.INHERITED_NAME,o.SORT_NUM, o.LEVEL_NUM,o.ADDRESS,o.TEL,o.REMARK
FROM sys_org o WHERE o.DELETED = 0 AND ORG_CODE = #{orgCode,jdbcType=VARCHAR}

mapper.update:
UPDATE sys_org SET PARENT_ID = #{parentId,jdbcType=NUMERIC},INHERITED_ID = #{inheritedId,jdbcType=VARCHAR},
INHERITED_NAME = #{inheritedName,jdbcType=VARCHAR},ORG_NAME = #{orgName,jdbcType=VARCHAR},
SORT_NUM = #{sortNum,jdbcType=NUMERIC},ORG_CODE = #{orgCode,jdbcType=VARCHAR},ADDRESS = #{address,jdbcType=VARCHAR},
TEL = #{tel,jdbcType=VARCHAR},
REMARK = #{remark,jdbcType=NUMERIC}, LAST_UPDATED_BY = #{lastUpdatedBy,jdbcType=NUMERIC}, LAST_UPDATED_DATE = #{lastUpdatedDate,jdbcType=TIMESTAMP}
WHERE ORG_ID = #{orgId,jdbcType=NUMERIC}

mapper.select:
SELECT o.ORG_ID, o.ORG_CODE, o.ORG_NAME, o.ADDRESS,o.TEL,COUNT(c.`CUST_NAME`) vip_num
 FROM SYS_ORG o left join crm_cust_info c on o.`ORG_ID`=c.`ORG_ID` and  o.DELETED = 0 WHERE o.ORG_ID = #{orgId,jdbcType=NUMERIC}
 GROUP BY o.ORG_ID, o.ORG_CODE, o.ORG_NAME,o.ADDRESS,o.TEL

SELECT o.ORG_ID, o.ORG_CODE, o.ORG_NAME,o.ADDRESS,o.TEL,COUNT(c.`CUST_NAME`) vip_num
 FROM SYS_ORG o left join crm_cust_info c on o.`ORG_ID`=c.`ORG_ID` and  o.DELETED = 0 WHERE o.PARENT_ID = #{parentId,jdbcType=NUMERIC}
 GROUP BY o.ORG_ID, o.ORG_CODE, o.ORG_NAME,o.ADDRESS,o.TEL
